// TestVocabConsistency_AttemptIDOnly asserts that no legacy run-id or runID
// Go identifiers remain in cli/internal/agent/ or cli/internal/bead/. These
// were renamed to attempt-id / attemptID as part of the vocabulary alignment
// that locked "attempt" as the canonical term.
func TestVocabConsistency_AttemptIDOnly(t *testing.T) {
	forbidden := regexp.MustCompile(`\brunID\b|\bRunID\b|\brun-id\b`)

	dirs := []string{
		".",                        // cli/internal/agent (this package)
		filepath.Join("..", "bead"), // cli/internal/bead
	}

	for _, dir := range dirs {
		entries, err := os.ReadDir(dir)
		require.NoError(t, err, "ReadDir %s", dir)
		for _, entry := range entries {
			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".go") {
				continue
			}
			path := filepath.Join(dir, entry.Name())
			data, err := os.ReadFile(path)
			require.NoError(t, err, "ReadFile %s", path)
			if loc := forbidden.FindIndex(data); loc != nil {
				t.Errorf("forbidden run-id vocabulary in %s at byte %d: %q",
					path, loc[0], data[loc[0]:min(loc[1]+20, len(data))])
			}
		}
	}
}

// TestExecutionDirs_AcceptBothNames verifies that execution-dir readers
// handle both legacy (pre-rename) and current attempt-id named directories
// under .ddx/executions/ without errors. The directory-name format has not
// changed (both eras use YYYYMMDDTHHMMSS-HHHHHHHH), but this test makes the
// invariant explicit and guards against any future name-validation regression.
func TestExecutionDirs_AcceptBothNames(t *testing.T) {
	projectRoot := t.TempDir()
	execRoot := filepath.Join(projectRoot, ".ddx", "executions")

	// Legacy-era dir (named as if created by the old newPreMergeRunID code).
	legacyDir := "20260101T000000-aabbccdd"
	// Current-era dir (named by GenerateAttemptID / newPreMergeAttemptID).
	currentDir := "20260201T120000-11223344"

	for _, name := range []string{legacyDir, currentDir} {
		dir := filepath.Join(execRoot, name)
		require.NoError(t, os.MkdirAll(dir, 0o755))
		require.NoError(t, os.WriteFile(
			filepath.Join(dir, "result.json"),
			[]byte(`{"status":"success","attempt_id":"`+name+`"}`),
			0o644,
		))
	}

	mgr := NewExecutionCleanupManager(projectRoot, nil)
	mgr.RetainDays = 0 // disable prune; we only test scanning

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.Equal(t, 2, summary.CompleteEvidenceDirs,
		"both legacy and current attempt-id named dirs must be counted as complete evidence")
}

